from pathlib import Path
from reportlab.lib import colors
from reportlab.lib.pagesizes import A4
from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
from reportlab.lib.units import mm
from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, PageBreak, Table, TableStyle

OUT = Path('output/pdf/OpsBrain-AI-PS8-Submission-Brief.pdf')
OUT.parent.mkdir(parents=True, exist_ok=True)
navy, blue, ink, muted, pale, line = '#0B1730', '#1268E8', '#172033', '#5D6B82', '#F1F6FF', '#D9E2F0'
s = getSampleStyleSheet()
s.add(ParagraphStyle(name='Cover', parent=s['Title'], fontName='Helvetica-Bold', fontSize=29, leading=34, textColor=colors.white, spaceAfter=8))
s.add(ParagraphStyle(name='Sub', parent=s['Normal'], fontSize=13, leading=18, textColor='#DCEAFF'))
s.add(ParagraphStyle(name='H1x', parent=s['Heading1'], fontName='Helvetica-Bold', fontSize=19, leading=23, textColor=navy, spaceAfter=9))
s.add(ParagraphStyle(name='H2x', parent=s['Heading2'], fontName='Helvetica-Bold', fontSize=11, leading=14, textColor=blue, spaceBefore=8, spaceAfter=4))
s.add(ParagraphStyle(name='Bodyx', parent=s['BodyText'], fontSize=9.3, leading=14, textColor=ink, spaceAfter=6))
s.add(ParagraphStyle(name='Smallx', parent=s['BodyText'], fontSize=8, leading=11, textColor=muted))
s.add(ParagraphStyle(name='Quote', parent=s['BodyText'], fontName='Helvetica-Bold', fontSize=13, leading=18, textColor=navy, leftIndent=10, borderColor='#12B8C4', borderWidth=3, borderPadding=8, spaceAfter=10))
s.add(ParagraphStyle(name='Cell', parent=s['BodyText'], fontSize=8.2, leading=11, textColor=ink))
s.add(ParagraphStyle(name='HeadCell', parent=s['BodyText'], fontName='Helvetica-Bold', fontSize=8.2, leading=11, textColor=colors.white))

def p(text, style='Bodyx'):
    return Paragraph(text, s[style])

def hf(c, d):
    c.saveState(); c.setStrokeColor(line); c.line(18*mm, 14*mm, 192*mm, 14*mm)
    c.setFont('Helvetica', 7.5); c.setFillColor(muted); c.drawString(18*mm, 9*mm, 'OpsBrain AI | ET AI Hackathon 2.0 | PS8'); c.drawRightString(192*mm, 9*mm, f'Page {d.page}'); c.restoreState()

def table(rows, widths, header=True):
    out = [[p(a, 'HeadCell') if i == 0 and header else p(a), p(b, 'HeadCell') if i == 0 and header else p(b)] for i,(a,b) in enumerate(rows)]
    t = Table(out, colWidths=widths)
    t.setStyle(TableStyle([('BACKGROUND',(0,0),(-1,0),blue if header else colors.white), ('ROWBACKGROUNDS',(0,1),(-1,-1),[colors.white,pale]), ('BOX',(0,0),(-1,-1),0.6,line), ('INNERGRID',(0,0),(-1,-1),0.35,line), ('VALIGN',(0,0),(-1,-1),'TOP'), ('PADDING',(0,0),(-1,-1),7)]))
    return t

doc = SimpleDocTemplate(str(OUT), pagesize=A4, rightMargin=18*mm, leftMargin=18*mm, topMargin=17*mm, bottomMargin=20*mm, title='OpsBrain AI - PS8 Submission Brief')
story = []
cover = Table([[p('OPSBRAIN AI','Cover'), p('ET AI HACKATHON 2.0','Smallx')], [p('A grounded operational memory for industrial teams.','Sub'), '']], colWidths=[125*mm,48*mm])
cover.setStyle(TableStyle([('BACKGROUND',(0,0),(-1,-1),navy),('LEFTPADDING',(0,0),(-1,-1),15),('RIGHTPADDING',(0,0),(-1,-1),15),('TOPPADDING',(0,0),(-1,-1),18),('BOTTOMPADDING',(0,0),(-1,-1),20),('VALIGN',(0,0),(-1,-1),'TOP')]))
story += [cover, Spacer(1,12), p('PS 8: AI for Industrial Knowledge Intelligence: Unified Asset & Operations Brain','H1x'), p('Submission brief | Working prototype | July 2026','Smallx'), Spacer(1,8), p('OpsBrain AI turns fragmented engineering records into connected evidence, then delivers maintenance, safety, compliance, and RCA answers with citations, confidence, and an inspectable retrieval trail.','Quote'), p('Executive summary','H1x'), p('Industrial teams keep critical knowledge in manuals, SOPs, incident reports, inspection notes, spreadsheets, and shift handovers. Finding evidence during a safety decision is slow, and generic chatbots cannot prove where an answer came from. OpsBrain automatically ingests operational documents, extracts metadata, creates adaptive chunks, builds entity relationships, and combines keyword, semantic, and graph retrieval. The Copilot answers from retrieved evidence and exposes the source document, page or chunk, confidence, related sources, and retrieval diagnostics.','Bodyx'), PageBreak()]
story += [p('The problem and the users','H1x'), p('<b>Users:</b> maintenance engineers, reliability teams, EHS and safety officers, plant managers, compliance teams, and incident investigators. <b>Pain:</b> fragmented records, repeated failures, slow RCA, and poor auditability.','Bodyx'), p('Product workflow','H2x'), table([('Step','Outcome'),('01 - Upload','PDF, DOCX, PPTX, XLSX, CSV, HTML, TXT, Markdown, or ZIP'),('02 - Understand','Extract content, metadata, sections, entities, and relationships'),('03 - Index','Create adaptive chunks for keyword, semantic, and graph retrieval'),('04 - Answer','Generate a grounded response with citations and confidence'),('05 - Act','Follow evidence through Assets, Graph, Compliance, RCA, and Insights')],[32*mm,140*mm]), Spacer(1,12), p('What the prototype demonstrates','H1x'), table([('Capability','Demonstrated implementation'),('Document intelligence','Multi-format extraction, metadata, adaptive chunks, and ingestion status'),('Enterprise RAG','Hybrid keyword/vector/graph retrieval, reranking, Gemini generation, and citations'),('Knowledge graph','Entity and relationship index for assets, incidents, procedures, departments, and regulations'),('Operational Copilot','Conversation context, source ranking, confidence, related documents, and retrieval trace'),('Asset, compliance, RCA','Connected asset history, evidence-led compliance gaps, and root-cause workflows'),('Product quality','Responsive desktop/mobile UI, authenticated routes, health endpoints, CI, and Docker topology')],[47*mm,125*mm]), PageBreak()]
story += [p('Architecture and innovation','H1x'), p('The product is evidence-first: ingestion, retrieval, generation, and UI are connected through a FastAPI contract rather than hardcoded demo responses.','Bodyx'), table([('Layer','Role'),('React + Firebase','Responsive authenticated product experience'),('FastAPI gateway','REST APIs, health/readiness, ingestion, intelligence, and RAG routes'),('Document pipeline','Extraction, metadata, adaptive chunking, and incremental indexing'),('Hybrid retrieval','Keyword + semantic/vector + entity/graph evidence with reranking'),('Gemini orchestration','Dynamic grounded prompt, answer, citations, confidence, and fallback'),('Operations views','Copilot, Documents, Assets, Graph, Compliance, RCA, and Insights')],[48*mm,124*mm]), Spacer(1,10), p('Innovation highlights','H2x'), p('<b>Evidence-first Copilot:</b> citations and confidence are first-class response fields. <b>Digital asset memory:</b> one asset view connects manuals, incidents, maintenance, risks, and recommendations. <b>Graph + RAG:</b> relationships retrieve context that plain keyword search misses. <b>Inspectable AI:</b> retrieval counts and source ranking let teams verify the answer path.','Bodyx'), p('Demo script','H2x'), p('<b>1.</b> Sign in with Firebase Email/Password. <b>2.</b> Open Documents. <b>3.</b> Ask: “What are the vibration alert thresholds for PMP-101?” <b>4.</b> Point out the cited document, chunk, confidence, and retrieval counts. <b>5.</b> Open the PMP-101 asset and Graph views. <b>6.</b> Finish with Compliance, RCA, and Insights.','Bodyx'), PageBreak()]
story += [p('Impact, verification, and submission','H1x'), p('Expected impact','H2x'), p('Reduce time spent searching records, improve consistency and auditability of maintenance and compliance decisions, reuse incident lessons across assets, and provide a practical foundation for QMS, sensor, and plant-system integrations.','Bodyx'), p('Verification evidence','H2x'), table([('Check','Result'),('Backend tests','30 passed'),('Frontend quality','TypeScript validation and production Vite build passed'),('Runtime','Health endpoint and live Gemini-grounded RAG query verified'),('Delivery','GitHub repository, CI, Docker Compose, architecture, requirements matrix, deck source, and demo storyboard included')],[48*mm,124*mm]), Spacer(1,12), p('Submission checklist','H2x'), p('Upload this PDF as the detailed document. Add the architecture diagram and presentation deck as additional files. Use the repository URL below. Record the demo using the script on page 3 and upload the 3–4 minute MP4 or a tested public link.','Bodyx'), p('GitHub: https://github.com/Pawan8010/ET-GEN-AI-HACKATHON','Bodyx'), p('Responsible scope','H2x'), p('The working prototype demonstrates multi-format document intelligence, hybrid RAG, graph retrieval, citations, responsive UI, asset intelligence, compliance/RCA workflows, and live Gemini integration. Scanned-image OCR/P&ID computer vision and external QMS connectors are documented extension points requiring plant drawings, model selection, or customer credentials. OpsBrain is decision support, not an autonomous safety controller.','Bodyx'), Spacer(1,12), p('Built for the ET AI Hackathon 2.0 | PS8','Smallx')]
doc.build(story, onFirstPage=hf, onLaterPages=hf)
print(OUT)
